31	template <typename T>
32	__global__ void extract_density(
33		const uint32_t n_elements,
34		const uint32_t density_stride,
35		const uint32_t rgbd_stride,
36		const T* __restrict__ density,
37		T* __restrict__ rgbd
38	) {
39		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
40		if (i >= n_elements) return;
41	
42		rgbd[i * rgbd_stride] = density[i * density_stride];
43	}
44	
45	template <typename T>
46	__global__ void extract_rgb(
47		const uint32_t n_elements,
48		const uint32_t rgb_stride,
49		const uint32_t output_stride,
50		const T* __restrict__ rgbd,
51		T* __restrict__ rgb
52	) {
53		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
54		if (i >= n_elements) return;
55	
56		const uint32_t elem_idx = i / 3;
57		const uint32_t dim_idx = i - elem_idx * 3;
58	
59		rgb[elem_idx*rgb_stride + dim_idx] = rgbd[elem_idx*output_stride + dim_idx];
60	}
61	
62	template <typename T>
63	__global__ void add_density_gradient(
64		const uint32_t n_elements,
65		const uint32_t rgbd_stride,
66		const T* __restrict__ rgbd,
67		const uint32_t density_stride,
68		T* __restrict__ density
69	) {
70		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
71		if (i >= n_elements) return;
72	
73		density[i * density_stride] += rgbd[i * rgbd_stride + 3];
74	}
75	
76	template <typename T>
77	class NerfNetwork : public Network<float, T> {
78	public:
79		using json = nlohmann::json;
80	
81		NerfNetwork(uint32_t n_pos_dims, uint32_t n_dir_dims, uint32_t n_extra_dims, uint32_t dir_offset, const json& pos_encoding, const json& dir_encoding, const json& density_network, const json& rgb_network) : m_n_pos_dims{n_pos_dims}, m_n_dir_dims{n_dir_dims}, m_dir_offset{dir_offset}, m_n_extra_dims{n_extra_dims} {
82			m_pos_encoding.reset(create_encoding<T>(n_pos_dims, pos_encoding, density_network.contains("otype") && (equals_case_insensitive(density_network["otype"], "FullyFusedMLP") || equals_case_insensitive(density_network["otype"], "MegakernelMLP")) ? 16u : 8u));
83			uint32_t rgb_alignment = minimum_alignment(rgb_network);
84			m_dir_encoding.reset(create_encoding<T>(m_n_dir_dims + m_n_extra_dims, dir_encoding, rgb_alignment));
85	
86			json local_density_network_config = density_network;
87			local_density_network_config["n_input_dims"] = m_pos_encoding->padded_output_width();
88			if (!density_network.contains("n_output_dims")) {
89				local_density_network_config["n_output_dims"] = 16;
90			}
91			m_density_network.reset(create_network<T>(local_density_network_config));
92	
93			m_rgb_network_input_width = next_multiple(m_dir_encoding->padded_output_width() + m_density_network->padded_output_width(), rgb_alignment);
94	
95			json local_rgb_network_config = rgb_network;
96			local_rgb_network_config["n_input_dims"] = m_rgb_network_input_width;
97			local_rgb_network_config["n_output_dims"] = 3;
98			m_rgb_network.reset(create_network<T>(local_rgb_network_config));
99	
100			m_density_model = std::make_shared<NetworkWithInputEncoding<T>>(m_pos_encoding, m_density_network);
101		}
102	
103		virtual ~NerfNetwork() { }
104	
105		void inference_mixed_precision_impl(cudaStream_t stream, const GPUMatrixDynamic<float>& input, GPUMatrixDynamic<T>& output, bool use_inference_params = true) override {
106			uint32_t batch_size = input.n();
107			GPUMatrixDynamic<T> density_network_input{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
108			GPUMatrixDynamic<T> rgb_network_input{m_rgb_network_input_width, batch_size, stream, m_dir_encoding->preferred_output_layout()};
109	
110			GPUMatrixDynamic<T> density_network_output = rgb_network_input.slice_rows(0, m_density_network->padded_output_width());
111			GPUMatrixDynamic<T> rgb_network_output{output.data(), m_rgb_network->padded_output_width(), batch_size, output.layout()};
112	
113			m_pos_encoding->inference_mixed_precision(
114				stream,
115				input.slice_rows(0, m_pos_encoding->input_width()),
116				density_network_input,
117				use_inference_params
118			);
119	
120			m_density_network->inference_mixed_precision(stream, density_network_input, density_network_output, use_inference_params);
121	
122			auto dir_out = rgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width());
123			m_dir_encoding->inference_mixed_precision(
124				stream,
125				input.slice_rows(m_dir_offset, m_dir_encoding->input_width()),
126				dir_out,
127				use_inference_params
128			);
129	
130			m_rgb_network->inference_mixed_precision(stream, rgb_network_input, rgb_network_output, use_inference_params);
131	
132			linear_kernel(extract_density<T>, 0, stream,
133				batch_size,
134				density_network_output.layout() == AoS ? density_network_output.stride() : 1,
135				output.layout() == AoS ? padded_output_width() : 1,
136				density_network_output.data(),
137				output.data() + 3 * (output.layout() == AoS ? 1 : batch_size)
138			);
139		}
140	
141		uint32_t padded_density_output_width() const {
142			return m_density_network->padded_output_width();
143		}
144	
145		std::unique_ptr<Context> forward_impl(cudaStream_t stream, const GPUMatrixDynamic<float>& input, GPUMatrixDynamic<T>* output = nullptr, bool use_inference_params = false, bool prepare_input_gradients = false) override {
146			// Make sure our temporary buffers have the correct size for the given batch size
147			uint32_t batch_size = input.n();
148	
149			auto forward = std::make_unique<ForwardContext>();
150	
151			forward->density_network_input = GPUMatrixDynamic<T>{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
152			forward->rgb_network_input = GPUMatrixDynamic<T>{m_rgb_network_input_width, batch_size, stream, m_dir_encoding->preferred_output_layout()};
153	
154			forward->pos_encoding_ctx = m_pos_encoding->forward(
155				stream,
156				input.slice_rows(0, m_pos_encoding->input_width()),
157				&forward->density_network_input,
158				use_inference_params,
159				prepare_input_gradients
160			);
161	
162			forward->density_network_output = forward->rgb_network_input.slice_rows(0, m_density_network->padded_output_width());
163			forward->density_network_ctx = m_density_network->forward(stream, forward->density_network_input, &forward->density_network_output, use_inference_params, prepare_input_gradients);
164	
165			auto dir_out = forward->rgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width());
166			forward->dir_encoding_ctx = m_dir_encoding->forward(
167				stream,
168				input.slice_rows(m_dir_offset, m_dir_encoding->input_width()),
169				&dir_out,
170				use_inference_params,
171				prepare_input_gradients
172			);
173	
174			if (output) {
175				forward->rgb_network_output = GPUMatrixDynamic<T>{output->data(), m_rgb_network->padded_output_width(), batch_size, output->layout()};
176			}
177	
178			forward->rgb_network_ctx = m_rgb_network->forward(stream, forward->rgb_network_input, output ? &forward->rgb_network_output : nullptr, use_inference_params, prepare_input_gradients);
179	
180			if (output) {
181				linear_kernel(extract_density<T>, 0, stream,
182					batch_size, m_dir_encoding->preferred_output_layout() == AoS ? forward->density_network_output.stride() : 1, padded_output_width(), forward->density_network_output.data(), output->data()+3
183				);
184			}
185	
186			return forward;
187		}
188	
189		void backward_impl(
190			cudaStream_t stream,
191			const Context& ctx,
192			const GPUMatrixDynamic<float>& input,
193			const GPUMatrixDynamic<T>& output,
194			const GPUMatrixDynamic<T>& dL_doutput,
195			GPUMatrixDynamic<float>* dL_dinput = nullptr,
196			bool use_inference_params = false,
197			GradientMode param_gradients_mode = GradientMode::Overwrite
198		) override {
199			const auto& forward = dynamic_cast<const ForwardContext&>(ctx);
200	
201			// Make sure our teporary buffers have the correct size for the given batch size
202			uint32_t batch_size = input.n();
203	
204			GPUMatrix<T> dL_drgb{m_rgb_network->padded_output_width(), batch_size, stream};
205			CUDA_CHECK_THROW(cudaMemsetAsync(dL_drgb.data(), 0, dL_drgb.n_bytes(), stream));
206			linear_kernel(extract_rgb<T>, 0, stream,
207				batch_size*3, dL_drgb.m(), dL_doutput.m(), dL_doutput.data(), dL_drgb.data()
208			);
209	
210			const GPUMatrixDynamic<T> rgb_network_output{(T*)output.data(), m_rgb_network->padded_output_width(), batch_size, output.layout()};
211			GPUMatrixDynamic<T> dL_drgb_network_input{m_rgb_network_input_width, batch_size, stream, m_dir_encoding->preferred_output_layout()};
212			m_rgb_network->backward(stream, *forward.rgb_network_ctx, forward.rgb_network_input, rgb_network_output, dL_drgb, &dL_drgb_network_input, use_inference_params, param_gradients_mode);
213	
214			// Backprop through dir encoding if it is trainable or if we need input gradients
215			if (m_dir_encoding->n_params() > 0 || dL_dinput) {
216				GPUMatrixDynamic<T> dL_ddir_encoding_output = dL_drgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width());
217				GPUMatrixDynamic<float> dL_ddir_encoding_input;
218				if (dL_dinput) {
219					dL_ddir_encoding_input = dL_dinput->slice_rows(m_dir_offset, m_dir_encoding->input_width());
220				}
221	
222				m_dir_encoding->backward(
223					stream,
224					*forward.dir_encoding_ctx,
225					input.slice_rows(m_dir_offset, m_dir_encoding->input_width()),
226					forward.rgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width()),
227					dL_ddir_encoding_output,
228					dL_dinput ? &dL_ddir_encoding_input : nullptr,
229					use_inference_params,
230					param_gradients_mode
231				);
232			}
233	
234			GPUMatrixDynamic<T> dL_ddensity_network_output = dL_drgb_network_input.slice_rows(0, m_density_network->padded_output_width());
235			linear_kernel(add_density_gradient<T>, 0, stream,
236				batch_size,
237				dL_doutput.m(),
238				dL_doutput.data(),
239				dL_ddensity_network_output.layout() == RM ? 1 : dL_ddensity_network_output.stride(),
240				dL_ddensity_network_output.data()
241			);
242	
243			GPUMatrixDynamic<T> dL_ddensity_network_input;
244			if (m_pos_encoding->n_params() > 0 || dL_dinput) {
245				dL_ddensity_network_input = GPUMatrixDynamic<T>{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
246			}
247	
248			m_density_network->backward(stream, *forward.density_network_ctx, forward.density_network_input, forward.density_network_output, dL_ddensity_network_output, dL_ddensity_network_input.data() ? &dL_ddensity_network_input : nullptr, use_inference_params, param_gradients_mode);
249	
250			// Backprop through pos encoding if it is trainable or if we need input gradients
251			if (dL_ddensity_network_input.data()) {
252				GPUMatrixDynamic<float> dL_dpos_encoding_input;
253				if (dL_dinput) {
254					dL_dpos_encoding_input = dL_dinput->slice_rows(0, m_pos_encoding->input_width());
255				}
256	
257				m_pos_encoding->backward(
258					stream,
259					*forward.pos_encoding_ctx,
260					input.slice_rows(0, m_pos_encoding->input_width()),
261					forward.density_network_input,
262					dL_ddensity_network_input,
263					dL_dinput ? &dL_dpos_encoding_input : nullptr,
264					use_inference_params,
265					param_gradients_mode
266				);
267			}
268		}
269	
270		void density(cudaStream_t stream, const GPUMatrixDynamic<float>& input, GPUMatrixDynamic<T>& output, bool use_inference_params = true) {
271			if (input.layout() != CM) {
272				throw std::runtime_error("NerfNetwork::density input must be in column major format.");
273			}
274	
275			uint32_t batch_size = output.n();
276			GPUMatrixDynamic<T> density_network_input{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
277	
278			m_density_model->set_jit_fusion(this->jit_fusion());
279			m_density_model->inference_mixed_precision(stream, input.slice_rows(0, m_pos_encoding->input_width()), output, use_inference_params);
280		}
281	
282		std::unique_ptr<Context> density_forward(cudaStream_t stream, const GPUMatrixDynamic<float>& input, GPUMatrixDynamic<T>* output = nullptr, bool use_inference_params = false, bool prepare_input_gradients = false) {
283			if (input.layout() != CM) {
284				throw std::runtime_error("NerfNetwork::density_forward input must be in column major format.");
285			}
286	
287			// Make sure our temporary buffers have the correct size for the given batch size
288			uint32_t batch_size = input.n();
289	
290			auto forward = std::make_unique<ForwardContext>();
291	
292			forward->density_network_input = GPUMatrixDynamic<T>{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
293	
294			forward->pos_encoding_ctx = m_pos_encoding->forward(
295				stream,
296				input.slice_rows(0, m_pos_encoding->input_width()),
297				&forward->density_network_input,
298				use_inference_params,
299				prepare_input_gradients
300			);
301	
302			if (output) {
303				forward->density_network_output = GPUMatrixDynamic<T>{output->data(), m_density_network->padded_output_width(), batch_size, output->layout()};
304			}
305	
306			forward->density_network_ctx = m_density_network->forward(stream, forward->density_network_input, output ? &forward->density_network_output : nullptr, use_inference_params, prepare_input_gradients);
307	
308			return forward;
309		}
310	
311		void density_backward(
312			cudaStream_t stream,
313			const Context& ctx,
314			const GPUMatrixDynamic<float>& input,
315			const GPUMatrixDynamic<T>& output,
316			const GPUMatrixDynamic<T>& dL_doutput,
317			GPUMatrixDynamic<float>* dL_dinput = nullptr,
318			bool use_inference_params = false,
319			GradientMode param_gradients_mode = GradientMode::Overwrite
320		) {
321			if (input.layout() != CM || (dL_dinput && dL_dinput->layout() != CM)) {
322				throw std::runtime_error("NerfNetwork::density_backward input must be in column major format.");
323			}
324	
325			const auto& forward = dynamic_cast<const ForwardContext&>(ctx);
326	
327			// Make sure our temporary buffers have the correct size for the given batch size
328			uint32_t batch_size = input.n();
329	
330			GPUMatrixDynamic<T> dL_ddensity_network_input;
331			if (m_pos_encoding->n_params() > 0 || dL_dinput) {
332				dL_ddensity_network_input = GPUMatrixDynamic<T>{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
333			}
334	
335			m_density_network->backward(stream, *forward.density_network_ctx, forward.density_network_input, output, dL_doutput, dL_ddensity_network_input.data() ? &dL_ddensity_network_input : nullptr, use_inference_params, param_gradients_mode);
336	
337			// Backprop through pos encoding if it is trainable or if we need input gradients
338			if (dL_ddensity_network_input.data()) {
339				GPUMatrixDynamic<float> dL_dpos_encoding_input;
340				if (dL_dinput) {
341					dL_dpos_encoding_input = dL_dinput->slice_rows(0, m_pos_encoding->input_width());
342				}
343	
344				m_pos_encoding->backward(
345					stream,
346					*forward.pos_encoding_ctx,
347					input.slice_rows(0, m_pos_encoding->input_width()),
348					forward.density_network_input,
349					dL_ddensity_network_input,
350					dL_dinput ? &dL_dpos_encoding_input : nullptr,
351					use_inference_params,
352					param_gradients_mode
353				);
354			}
355		}
