357		void set_params_impl(T* params, T* inference_params, T* gradients) override {
358			m_density_model->set_params(params, inference_params, gradients);
359	
360			size_t offset = 0;
361			m_density_network->set_params(params + offset, inference_params + offset, gradients + offset);
362			offset += m_density_network->n_params();
363	
364			m_rgb_network->set_params(params + offset, inference_params + offset, gradients + offset);
365			offset += m_rgb_network->n_params();
366	
367			m_pos_encoding->set_params(params + offset, inference_params + offset, gradients + offset);
368			offset += m_pos_encoding->n_params();
369	
370			m_dir_encoding->set_params(params + offset, inference_params + offset, gradients + offset);
371			offset += m_dir_encoding->n_params();
372		}
373	
374		void initialize_params(pcg32& rnd, float* params_full_precision, float scale = 1) override {
375			m_density_network->initialize_params(rnd, params_full_precision, scale);
376			params_full_precision += m_density_network->n_params();
377	
378			m_rgb_network->initialize_params(rnd, params_full_precision, scale);
379			params_full_precision += m_rgb_network->n_params();
380	
381			m_pos_encoding->initialize_params(rnd, params_full_precision, scale);
382			params_full_precision += m_pos_encoding->n_params();
383	
384			m_dir_encoding->initialize_params(rnd, params_full_precision, scale);
385			params_full_precision += m_dir_encoding->n_params();
386		}
387	
388		size_t n_params() const override {
389			return m_pos_encoding->n_params() + m_density_network->n_params() + m_dir_encoding->n_params() + m_rgb_network->n_params();
390		}
391	
392		uint32_t padded_output_width() const override {
393			return std::max(m_rgb_network->padded_output_width(), (uint32_t)4);
394		}
395	
396		uint32_t input_width() const override {
397			return m_dir_offset + m_n_dir_dims + m_n_extra_dims;
398		}
399	
400		uint32_t output_width() const override {
401			return 4;
402		}
403	
404		uint32_t n_extra_dims() const {
405			return m_n_extra_dims;
406		}
407	
408		uint32_t required_input_alignment() const override {
409			return 1; // No alignment required due to encoding
410		}
411	
412		std::vector<std::pair<uint32_t, uint32_t>> layer_sizes() const override {
413			auto layers = m_density_network->layer_sizes();
414			auto rgb_layers = m_rgb_network->layer_sizes();
415			layers.insert(layers.end(), rgb_layers.begin(), rgb_layers.end());
416			return layers;
417		}
418	
419		uint32_t width(uint32_t layer) const override {
420			if (layer == 0) {
421				return m_pos_encoding->padded_output_width();
422			} else if (layer < m_density_network->num_forward_activations() + 1) {
423				return m_density_network->width(layer - 1);
424			} else if (layer == m_density_network->num_forward_activations() + 1) {
425				return m_rgb_network_input_width;
426			} else {
427				return m_rgb_network->width(layer - 2 - m_density_network->num_forward_activations());
428			}
429		}
430	
431		uint32_t num_forward_activations() const override {
432			return m_density_network->num_forward_activations() + m_rgb_network->num_forward_activations() + 2;
433		}
434	
435		std::pair<const T*, MatrixLayout> forward_activations(const Context& ctx, uint32_t layer) const override {
436			const auto& forward = dynamic_cast<const ForwardContext&>(ctx);
437			if (layer == 0) {
438				return {forward.density_network_input.data(), m_pos_encoding->preferred_output_layout()};
439			} else if (layer < m_density_network->num_forward_activations() + 1) {
440				return m_density_network->forward_activations(*forward.density_network_ctx, layer - 1);
441			} else if (layer == m_density_network->num_forward_activations() + 1) {
442				return {forward.rgb_network_input.data(), m_dir_encoding->preferred_output_layout()};
443			} else {
444				return m_rgb_network->forward_activations(*forward.rgb_network_ctx, layer - 2 - m_density_network->num_forward_activations());
445			}
446		}
